function T(k){const lang=I18N[state.lang]||I18N.gl;return lang[k]??I18N.es[k]??I18N.gl[k]??k};
function N(k){const lang=I18N[state.lang]||I18N.gl;return lang.nav?.[k]??I18N.es.nav[k]??k}
function normalise(s=''){return String(s).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9ñ\s]/g,' ').replace(/\s+/g,' ').trim()}
function tokens(s){return normalise(s).split(' ').filter(Boolean)}
function escapeHTML(s){return String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#039;','"':'&quot;'}[c]))}
function sourceById(id){return state.data.official_sources.find(s=>s.id===id)}
function sourceLinks(ids=[]){return `<div class="link-stack">${ids.map(id=>{const s=sourceById(id);return s?`<a class="source-link" target="_blank" rel="noopener noreferrer" href="${s.url}"><strong>${escapeHTML(s.title)}</strong><span>${escapeHTML(s.use)}</span></a>`:''}).join('')}</div>`}
function levenshtein(a,b){a=normalise(a);b=normalise(b);const dp=Array.from({length:a.length+1},()=>Array(b.length+1).fill(0));for(let i=0;i<=a.length;i++)dp[i][0]=i;for(let j=0;j<=b.length;j++)dp[0][j]=j;for(let i=1;i<=a.length;i++)for(let j=1;j<=b.length;j++)dp[i][j]=Math.min(dp[i-1][j]+1,dp[i][j-1]+1,dp[i-1][j-1]+(a[i-1]===b[j-1]?0:1));return dp[a.length][b.length]}
function sim(a,b){a=normalise(a);b=normalise(b);if(!a||!b)return 0;if(a.includes(b)||b.includes(a))return 1;let best=1-levenshtein(a,b)/Math.max(a.length,b.length);for(const x of tokens(a))for(const y of tokens(b))if(x.length>2&&y.length>2)best=Math.max(best,1-levenshtein(x,y)/Math.max(x.length,y.length));return best}
function scoreProgram(p,q){if(!q)return .55;const fields=[p.name,p.family,p.level,...(p.keywords||[])];if(fields.some(f=>normalise(f).includes(normalise(q))))return 1.35;return Math.max(...fields.map(f=>sim(q,f)))}
function programs(q='',type='all',family='all'){return state.data.studies.map(p=>{let score=scoreProgram(p,q);if(type!=='all'&&p.type!==type)score-=.55;if(family!=='all'&&normalise(p.family)!==normalise(family))score-=.35;if(!q&&(type!=='all'||family!=='all'))score+=.4;return{...p,score}}).filter(p=>p.score>.36).sort((a,b)=>b.score-a.score).slice(0,20)}
function isAmbiguous(list){return list.length>1&&(list[0].score-list[1].score<.18||list[0].score<1.15)}
function renderSourceLinks(ids){return sourceLinks(ids)}
function availabilityHTML(p){const av=p.availability_by_province||{};return Object.keys(av).length?`<div class="availability"><h4>${T('availability')}</h4>${Object.entries(av).map(([prov,rows])=>`<div class="province-block"><strong>${escapeHTML(prov)}</strong><ul>${(Array.isArray(rows)?rows:[rows]).map(r=>typeof r==='object'?`<li>${escapeHTML(r.city)} · ${escapeHTML(r.center)} ${r.note?`<em>(${escapeHTML(r.note)})</em>`:''}</li>`:`<li>${escapeHTML(r)}</li>`).join('')}</ul></div>`).join('')}</div>`:''}
function ponderationHTML(p){return p.ponderation_subjects?.length?`<p><strong>${T('ponderations')}:</strong> ${p.ponderation_subjects.map(x=>`${escapeHTML(x.subject)} (${escapeHTML(x.weight)})`).join(', ')}</p>`:''}
function programCard(p,approx=false){return `<article class="result-card">${approx?`<p class="eyebrow">${T('maybe')}: ${escapeHTML(p.name)}</p>`:''}<h3>${escapeHTML(p.name)}</h3><div class="badges"><span class="badge">${escapeHTML(p.level)}</span><span class="badge">${escapeHTML(p.family)}</span></div><p><strong>${T('route')}:</strong> ${escapeHTML(p.route)}</p><p><strong>${T('subjects')}:</strong> ${(p.subjects||[]).map(escapeHTML).join(', ')}</p>${ponderationHTML(p)}<p><strong>${T('important')}:</strong> ${escapeHTML(p.regulated)}</p><p><strong>Demanda / empleo:</strong> ${escapeHTML(p.demand)}</p>${availabilityHTML(p)}<p class="warning-box small">${T('officialNote')}</p><div class="result-actions"><button type="button" class="button pdf-button" onclick="exportPDF('studyResults','ITINERA · ${escapeHTML(p.name)}')">${T('pdf')}</button><button type="button" class="button action-sim" onclick="simulateProgram('${p.id}')">${T('sim')}</button></div>${sourceLinks(p.sources)}</article>`}
async function runSearch(){const q=document.getElementById('studySearch').value.trim();const type=document.getElementById('studyTypeFilter').value;const family=document.getElementById('familyFilter').value;const out=document.getElementById('studyResults');if(!q&&type==='all'&&family==='all'){out.innerHTML=`<div class="warning-box">${T('finderDescription')}</div>`;return}out.innerHTML='<div class="result-card"><p>Buscando…</p></div>';let list=programs(q,type,family);try{const params=new URLSearchParams({q,type,family,residence:document.getElementById('residenceFilter').value||''});const res=await fetch(`/.netlify/functions/studies-search?${params}`);const data=await res.json();if(data?.last_updated_at)updateBadge(data.last_updated_at);if(data?.results?.length)list=data.results;}catch(e){}if(!list.length){out.innerHTML=`<article class="result-card"><h3>${escapeHTML(T('finderTitle'))}</h3><p>${escapeHTML(T('officialNote'))}</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','xunta-fp-centros','qedu','ruct','ciug-admision'])}</article>`;return}const exact=q&&list.some(p=>normalise(p.name).includes(normalise(q))||(p.keywords||[]).some(k=>normalise(k)===normalise(q)));out.innerHTML=list.map((p,i)=>programCard(p,Boolean(q&&i===0&&!exact&&p.score>.45))).join('')}
function renderSelects(){const langSel=document.getElementById('languageSelect');langSel.innerHTML=[['gl','Galego'],['es','Castellano'],['en','English'],['fr','Français'],['pl','Polski'],['de','Deutsch']].map(([v,l])=>`<option value="${v}">${l}</option>`).join('');langSel.value=state.lang;const fontSel=document.getElementById('fontSelect');fontSel.innerHTML=Object.entries(I18N[state.lang]?.fonts||I18N.es.fonts).map(([v,l])=>`<option value="${v}">${l}</option>`).join('');fontSel.value=state.font;const type=document.getElementById('studyTypeFilter');type.innerHTML=[['all',T('all')],['fpgm','FP grado medio'],['fpgs','FP grado superior'],['grado','Grado'],['master','Máster']].map(([v,l])=>`<option value="${v}">${l}</option>`).join('');const fam=document.getElementById('familyFilter');const families=[...new Set(state.data.studies.map(p=>p.family))].sort();fam.innerHTML=`<option value="all">${T('allFamilies')}</option>`+families.map(f=>`<option value="${escapeHTML(f)}">${escapeHTML(f)}</option>`).join('')}
