function groupedOfficialMenu(){
  const menu=document.querySelector('.official-menu');
  if(!menu || menu.dataset.grouped==='1') return;
  const items=[...menu.querySelectorAll('a')];
  const byId=id=>items.find(a=>a.id===id);
  const groups=[
    ['Orientación general',['navItinerarios','navBach','navPonderaciones']],
    ['Estudios y oferta',['navEstudios','navFP','navUniversidad']],
    ['Acceso, ayudas y cambios',['navPruebas','navBecas','navCupos','navConvalidaciones']]
  ];
  menu.innerHTML=groups.map(([title,ids])=>`<div class="menu-group"><p>${escapeHTML(title)}</p>${ids.map(id=>byId(id)?.outerHTML||'').join('')}</div>`).join('');
  menu.dataset.grouped='1';
}

