ponderationHTML = function(p){
  const arr = (p.ponderation_subjects || []).filter(Boolean);
  if(!arr.length) return '';
  const clean = arr.map(x => {
    if(typeof x === 'string') return escapeHTML(x);
    const subject = x.subject || x.name || x.materia || '';
    const weight = x.weight || x.ponderacion || x.value || '';
    if(!subject && !weight) return '';
    return `${escapeHTML(subject)}${weight ? ` (${escapeHTML(weight)})` : ''}`;
  }).filter(Boolean);
  if(!clean.length) return '';
  return `<p><strong>${T('ponderations')}:</strong> ${clean.join(', ')}</p>`;
};

