  const URLS={ruct:'https://universidades.sede.gob.es/pagina/index/directorio/Proc_Ruct',qedu:'https://www.ciencia.gob.es/qedu',ciug:'https://www.ciug.gal/admision-sug',xunta:'https://www.edu.xunta.gal/fp/oferta-fp',todofp:'https://www.todofp.es/que-estudiar.html'};
  function v25Menu(){const nav=document.getElementById('mainNav');if(!nav)return;nav.className='main-nav shell v25-menu-nav';nav.innerHTML=`<details class="v25-menu"><summary>${escapeHTML(L('menu'))}</summary><div class="v25-menu-panel"><section><h3>${escapeHTML(L('tools'))}</h3><a href="#inicio" data-route="inicio">${escapeHTML(L('searchSimple'))}</a><a href="#aventura" data-route="aventura">${escapeHTML(L('simulator'))}</a><a href="#asistente" data-route="asistente">${escapeHTML(L('bot'))}</a></section><section><h3>${escapeHTML(L('officialLinks'))}</h3><a href="#fuentes" data-route="fuentes">${escapeHTML(L('sourcesFooter'))}</a><a href="${URLS.ruct}" target="_blank" rel="noopener noreferrer">RUCT</a><a href="${URLS.qedu}" target="_blank" rel="noopener noreferrer">QEDU</a><a href="${URLS.ciug}" target="_blank" rel="noopener noreferrer">CIUG</a><a href="${URLS.xunta}" target="_blank" rel="noopener noreferrer">Xunta FP</a><a href="${URLS.todofp}" target="_blank" rel="noopener noreferrer">TodoFP</a></section></div></details>`;bindRoutes();nav.querySelectorAll('[data-route]').forEach(a=>a.addEventListener('click',()=>nav.querySelector('details')?.removeAttribute('open')));}
  function v25KeepOnlyCore(){document.body.classList.add('v25-clean');['headerSourcesBtn','headerFaqBtn'].forEach(id=>{const el=document.getElementById(id);if(el)el.style.display='none';});const keep=new Set(['inicio','aventura','asistente','fuentes']);document.querySelectorAll('main > section.view').forEach(sec=>{if(!keep.has(sec.id))sec.classList.add('v25-hidden-section');else sec.classList.remove('v25-hidden-section');});const title=document.getElementById('heroTitle'),lead=document.getElementById('heroLead');if(title)title.textContent=L('coverTitle');if(lead)lead.textContent=L('coverLead');const search=document.getElementById('studySearch');if(search)search.placeholder=L('searchPlaceholder');const ft=document.getElementById('finderTitle'),fd=document.getElementById('finderDescription');if(ft)ft.textContent=L('searchSimple');if(fd)fd.textContent='';document.querySelector('.cards-panel')?.classList.add('v25-hidden-section');['v23Dashboard','coveragePanel','v022StatusPanel','v23UniversityPanel','v23CiugPanel','v23FpPanel','v022UniversityPanel','v022CiugPanel','v022FpPanel'].forEach(id=>document.getElementById(id)?.remove());}
  function kind(p){const t=String(p?.type||'').toLowerCase(),l=String(p?.level||'').toLowerCase();if(t==='grado'||/universidad|grao universitario|grado universitario/.test(l))return'grado';if(t==='fpgs'||/grado superior/.test(l))return'fpgs';if(t==='fpgm'||/grado medio/.test(l))return'fpgm';if(t==='fpb'||/básic|basic/.test(l))return'fpb';if(t.includes('especializacion')||/especializ/.test(l))return'especializacion';if(t==='master'||/máster|master/.test(l))return'master';return t||'otro';}
  function mtext(p){return normalise([p?.name,p?.family,p?.branch,p?.keywords?.join(' '),p?.regulated,p?.route].filter(Boolean).join(' '));}
  function bachFor(p){const q=mtext(p);if(/arquitect|ingenier|informat|matematic|fisic|industrial|tecnolog|aeronaut|telecom|edificacion|dibujo|debuxo/.test(q))return{name:'Bachillerato de Ciencias y Tecnología',why:'Recomendable para arquitectura, ingeniería, tecnología, informática y estudios con Matemáticas, Física o Dibujo Técnico.'};if(/medicin|enfermer|farmac|biolog|quimic|veterinar|odontolog|fisioterapia|salud|sanidad|nutricion|psicolog/.test(q))return{name:'Bachillerato de Ciencias y Tecnología',why:'Recomendable para Ciencias de la Salud. En Psicología conviene revisar Biología y Matemáticas aplicadas según CIUG.'};if(/derecho|dereito|econom|empresa|administracion|marketing|turismo|educacion|pedagog|trabajo social|sociolog|periodismo|comunicacion|criminolog/.test(q))return{name:'Bachillerato de Humanidades y Ciencias Sociales',why:'Vía coherente para ciencias sociales, jurídicas, educación, empresa, economía y comunicación.'};if(/filolog|historia|filosof|humanidad|latin|lingua|lengua|traduc|patrimonio/.test(q))return{name:'Bachillerato de Humanidades y Ciencias Sociales',why:'Vía coherente para humanidades, lenguas, historia y estudios culturales.'};if(/arte|diseñ|diseno|música|musica|danza|audiovisual|bellas artes|escenic/.test(q))return{name:'Bachillerato de Artes',why:'Vía coherente para enseñanzas artísticas, diseño, música, artes escénicas y audiovisual.'};return{name:'Bachillerato según la rama del estudio',why:'Elige la modalidad con mejor base y mejores ponderaciones para la meta concreta. Verifica CIUG o la fuente autonómica.'};}
  function ro(title,steps,note,sources){return{title,steps:steps.filter(Boolean),note:note||'',sources:sources||[]};}
  function routesFor(p){const k=kind(p),b=bachFor(p),r=[];if(k==='grado'){r.push(ro('Ruta universitaria directa',['ESO con título',b.name,'ABAU/EBAU y admisión universitaria',p.name],b.why,['ciug-admision','qedu','ruct']));r.push(ro('Ruta desde FP superior',['ESO con título','Ciclo formativo de grado medio o acceso equivalente','Ciclo formativo de grado superior relacionado','Admisión a grado universitario desde FP superior',p.name],'Puede requerir fase voluntaria de ABAU si la nota es alta.',['ciug-admision','qedu','ruct']));r.push(ro('Ruta por prueba de acceso a ciclo superior',['Formación previa','Prueba de acceso a ciclo superior si cumples edad y requisitos','Ciclo formativo de grado superior relacionado','Admisión universitaria desde FP superior',p.name],'Contempla acceder a ciclo superior sin pasar por ciclo medio ni Bachillerato.',['xunta-fp-ciclos','ciug-admision']));}
    else if(k==='fpgs'){r.push(ro('Ruta desde Bachillerato',['ESO con título','Bachillerato',p.name],'Vía habitual y corta si orientas tu camino a un ciclo superior.',['xunta-fp-oferta-2025-2026']));r.push(ro('Ruta desde grado medio',['ESO con título','Ciclo formativo de grado medio relacionado o compatible',p.name],'Permite progresar desde FP sin hacer Bachillerato.',['xunta-fp-ciclos']));r.push(ro('Ruta por prueba de acceso',['Formación previa','Prueba de acceso a ciclo superior si cumples edad y requisitos',p.name],'Permite acceder a ciclo superior sin pasar por ciclo medio ni Bachillerato, cuando se cumplen requisitos.',['xunta-fp-ciclos']));}
    else if(k==='fpgm'){r.push(ro('Ruta directa desde ESO',['ESO con título',p.name],'Vía directa habitual hacia grado medio.',['xunta-fp-oferta-2025-2026']));r.push(ro('Ruta mediante prueba de acceso',['Sin título de ESO o vía alternativa','Prueba de acceso a grado medio si cumples requisitos',p.name],'Útil cuando no se dispone de titulación ordinaria.',['xunta-fp-ciclos']));r.push(ro('Ruta desde FP básica',['FP básica relacionada','Acceso a grado medio',p.name],'Vía gradual de continuidad.',['todofp-familias']));}
    else if(k==='fpb')r.push(ro('Ruta de FP básica',['ESO cursada','Propuesta u orientación del centro según requisitos',p.name],'Vía inicial profesionalizadora.',['todofp-familias','xunta-fp-oferta-2025-2026']));
    else if(k==='especializacion')r.push(ro('Ruta desde FP previa',['Ciclo formativo de grado medio o superior exigido en la ficha oficial',p.name],'Cada curso exige titulaciones concretas de acceso. Verifica TodoFP.',['todofp-cursos-especializacion']));
    else if(k==='master')r.push(ro('Ruta de máster',['Grado universitario oficial compatible','Admisión al máster',p.name],'Si es habilitante, verifica RUCT, universidad y normativa profesional.',['ruct','qedu']));
    else r.push(ro('Ruta orientativa',['Etapa actual','Requisitos de acceso oficiales',p.name],'Verifica la fuente oficial antes de decidir.',['qedu','ruct','xunta-fp-oferta-2025-2026']));return r;}
  function adapt(routes,start,p){const k=kind(p);if(start==='bach')return routes.map(r=>({...r,steps:r.steps.filter(s=>!/^ESO/.test(s)).map(s=>s==='Bachillerato'?'Bachillerato actual':s)}));if(start==='fpgm'){if(k==='fpgs')return[ro('Desde grado medio',['Ciclo formativo de grado medio actual',p.name],'Ruta natural de continuidad dentro de FP.',['xunta-fp-ciclos'])].concat(routes);if(k==='grado')return[ro('Desde grado medio hacia universidad',['Ciclo formativo de grado medio actual','Ciclo formativo de grado superior relacionado','Admisión universitaria desde FP superior',p.name],'No exige Bachillerato, pero puede requerir mejorar nota mediante fase voluntaria.',['ciug-admision','qedu'])].concat(routes);}if(start==='fpgs'&&k==='grado')return[ro('Desde FP superior a grado',['Ciclo formativo de grado superior actual','Admisión universitaria desde FP superior','Fase voluntaria ABAU si necesitas subir nota',p.name],'Ruta directa desde FP superior a universidad.',['ciug-admision','qedu','ruct'])].concat(routes);if(start==='eso_sin')return routes.map(r=>({...r,steps:['Regularizar acceso: adultos, FP básica o prueba según edad y requisitos'].concat(r.steps.filter(s=>!/^ESO/.test(s)))}));return routes;}
  function score(r){return r.steps.length+(r.title.toLowerCase().includes('prueba')?.3:0);}
  renderAdventure=function(){const starts=[['eso_cursando','Estoy cursando ESO'],['eso_titulo','Tengo título de ESO'],['eso_sin','No tengo título de ESO'],['bach','Estoy en Bachillerato'],['fpgm','Estoy en Grado Medio'],['fpgs','Estoy en Grado Superior'],['grado','Ya tengo un grado']];const sb=document.getElementById('adventureStartOptions');if(sb){document.getElementById('adventureStartTitle').textContent=L('start');sb.innerHTML=starts.map(([id,l])=>`<button class="${state.adventure.start===id?'active':''}" data-start="${id}">${escapeHTML(l)}</button>`).join('');sb.querySelectorAll('[data-start]').forEach(b=>b.onclick=()=>{state.adventure.start=b.dataset.start;state.adventure.step=2;renderAdventure();});}const gt=document.getElementById('adventureGoalTitle'),inp=document.getElementById('adventureGoalSearch');if(gt)gt.textContent=L('goal');if(inp){inp.placeholder=L('chooseGoal');inp.oninput=e=>{state.adventure.goalText=e.target.value;state.adventure.selectedProgramId=null;renderAdventure();};}const go=document.getElementById('adventureGoalOptions');if(go){go.innerHTML=['psicología','enfermería','arquitectura','derecho','electricidad','soldadura','informática','educación infantil'].map(g=>`<button data-goal="${escapeHTML(g)}">${escapeHTML(g)}</button>`).join('');go.querySelectorAll('[data-goal]').forEach(b=>b.onclick=()=>{state.adventure.goalText=b.dataset.goal;if(inp)inp.value=b.dataset.goal;state.adventure.selectedProgramId=null;state.adventure.step=3;renderAdventure();});}const matches=programs(state.adventure.goalText),dis=document.getElementById('adventureDisambiguation');if(dis){if(state.adventure.goalText&&matches.length>1){dis.innerHTML=matches.slice(0,5).map(p=>`<button class="choice-card" data-pid="${p.id}">${escapeHTML(p.name)}<br><small>${escapeHTML([p.family,p.level].filter(Boolean).join(' · '))}</small></button>`).join('');dis.querySelectorAll('[data-pid]').forEach(b=>b.onclick=()=>{state.adventure.selectedProgramId=b.dataset.pid;state.adventure.step=3;renderAdventure();});}else dis.innerHTML='';}const qb=document.getElementById('adventureQuestions');if(qb){document.getElementById('adventureQuestionsTitle').textContent=L('routeMode');const mode=state.adventure.adjustment||'direct';qb.innerHTML=[['direct',L('directRoute')],['all',L('allRoutes')]].map(([id,l])=>`<button class="${mode===id?'active':''}" data-adjust="${id}">${escapeHTML(l)}</button>`).join('');qb.querySelectorAll('[data-adjust]').forEach(b=>b.onclick=()=>{state.adventure.adjustment=b.dataset.adjust;renderAdventureResult();renderAdventure();});}document.querySelectorAll('.wizard-step').forEach((el,i)=>el.classList.toggle('active',i+1===Math.min(state.adventure.step||1,3)));document.querySelectorAll('.wizard-progress span').forEach((el,i)=>el.classList.toggle('active',i+1<=Math.min(state.adventure.step||1,3)));renderAdventureResult();};
  renderAdventureResult=function(){const stage=document.getElementById('adventureResult');if(!stage)return;const p=selectedProgram();if(!state.adventure.goalText){stage.innerHTML=`<div class="v25-route-empty"><h2>${escapeHTML(L('simulator'))}</h2><p>${escapeHTML(L('noGoal'))}</p></div>`;return;}if(!p){stage.innerHTML=`<div class="v25-route-empty"><h2>${escapeHTML(L('simulator'))}</h2><p>${escapeHTML(T('officialNote'))}</p>${sourceLinks(['qedu','ruct','xunta-fp-oferta-2025-2026','ciug-admision'])}</div>`;return;}const b=bachFor(p);let routes=adapt(routesFor(p),state.adventure.start,p);routes=[...new Map(routes.map(r=>[r.title+'|'+r.steps.join('>'),r])).values()];const all=(state.adventure.adjustment||'direct')==='all';if(!all)routes=routes.sort((a,b)=>score(a)-score(b)).slice(0,1);stage.innerHTML=`<article class="v25-route-board"><header><p class="eyebrow">${escapeHTML(L('simulator'))}</p><h2>${escapeHTML(p.name)}</h2><p>${escapeHTML(L('simLead'))}</p></header><section class="v25-bach-card"><span>${escapeHTML(L('bachRecommended'))}</span><strong>${escapeHTML(b.name)}</strong><p>${escapeHTML(b.why)}</p></section><section class="v25-route-list"><h3>${escapeHTML(L('accessRoutes'))}</h3>${routes.map((r,i)=>`<article class="v25-route-option"><div class="v25-route-title"><span>${i+1}</span><strong>${escapeHTML(r.title)}</strong></div><ol>${r.steps.map(s=>`<li>${escapeHTML(s)}</li>`).join('')}</ol>${r.note?`<p>${escapeHTML(r.note)}</p>`:''}${sourceLinks(r.sources||[])}</article>`).join('')}</section><p class="v25-route-warning">${escapeHTML(all?L('allWarning'):L('shortWarning'))}</p></article>`;};
  function v25SimulatorClean(){const adv=document.getElementById('aventura');if(!adv)return;adv.classList.add('v25-simulator-view');const desc=document.getElementById('adventureDescription');if(desc)desc.textContent=L('simLead');renderAdventure();}
  function v25Apply(){v25Menu();v25KeepOnlyCore();v25SimulatorClean();const badge=document.getElementById('updateBadge');if(badge){badge.textContent='ITINERA v0.25';badge.title='Versión simplificada: buscador, simulador, ItineraBot y fuentes oficiales.';}}
