    if(!state.adventure.goalText){
      stage.innerHTML=`<div class="v25-route-empty v251-route-empty"><h2>${escapeHTML(L('simulator'))}</h2><p>${escapeHTML(L('noGoal'))}</p></div>`;
      return;
    }
    const {program:p, bach, routes} = getCurrentRoutesV251();
