      stage.innerHTML=`<div class="v25-route-empty v251-route-empty"><h2>${escapeHTML(L('simulator'))}</h2><p>${escapeHTML(T('officialNote'))}</p>${sourceLinks(['qedu','ruct','xunta-fp-oferta-2025-2026','ciug-admision'])}</div>`;
